import { Link, useNavigate, useLocation } from "react-router-dom";
import { useState } from "react";
import { Menu, X } from "lucide-react";

export default function Navbar() {

  const navigate = useNavigate();
  const location = useLocation();
  const pathname = location.pathname;

  const accessToken = localStorage.getItem("accessToken");
  const storedUser = localStorage.getItem("user");
  const user = storedUser ? JSON.parse(storedUser) : null;

  const isLoggedIn = Boolean(accessToken);
  const isAdmin = user?.role === "admin";

  const [open, setOpen] = useState(false);

  const logout = () => {

    localStorage.removeItem("accessToken");
    localStorage.removeItem("refreshToken");
    localStorage.removeItem("user");

    navigate("/login", { replace: true });

  };

  return (

    <nav className="bg-white shadow-md border-b sticky top-0 z-50">

      <div className="max-w-7xl mx-auto px-6 py-3 flex items-center justify-between">

        {/* LOGO */}

        <Link
          to="/dashboard"
          className="text-2xl font-extrabold tracking-wide hover:scale-105 transition"
        >
          <span className="text-blue-600">we</span>
          <span className="text-gray-900">FOUND</span>
          <span className="text-green-600">it</span>
        </Link>


        {/* DESKTOP NAV */}

        <div className="hidden md:flex items-center gap-6 font-medium">

          <NavItem to="/dashboard" active={pathname === "/dashboard"}>
            Dashboard
          </NavItem>

          <NavItem to="/my-posts" active={pathname === "/my-posts"}>
            My Posts
          </NavItem>

          <NavItem to="/returned" active={pathname === "/returned"}>
            Returned Items
          </NavItem>

          <NavItem to="/about" active={pathname === "/about"}>
            About
          </NavItem>

          {isAdmin && (
            <NavItem to="/admin" active={pathname === "/admin"}>
              Admin
            </NavItem>
          )}

        </div>


        {/* USER SECTION */}

        {isLoggedIn && (

          <div className="hidden md:flex items-center gap-4">

            <span className="font-semibold text-gray-700">
              {user?.name}
            </span>

            {isAdmin && (
              <span className="text-xs bg-purple-100 text-purple-700 px-2 py-1 rounded-full font-bold">
                ADMIN
              </span>
            )}

            <button
              onClick={logout}
              className="bg-red-500 hover:bg-red-600 text-white px-4 py-1.5 rounded-lg transition"
            >
              Logout
            </button>

          </div>

        )}


        {/* MOBILE MENU BUTTON */}

        <button
          onClick={() => setOpen(!open)}
          className="md:hidden"
        >
          {open ? <X size={26}/> : <Menu size={26}/>}
        </button>

      </div>


      {/* MOBILE MENU */}

      {open && (

        <div className="md:hidden border-t bg-white">

          <MobileItem to="/dashboard" setOpen={setOpen}>
            Dashboard
          </MobileItem>

          <MobileItem to="/my-posts" setOpen={setOpen}>
            My Posts
          </MobileItem>

          <MobileItem to="/returned" setOpen={setOpen}>
            Returned Items
          </MobileItem>

          <MobileItem to="/about" setOpen={setOpen}>
            About
          </MobileItem>

          {isAdmin && (
            <MobileItem to="/admin" setOpen={setOpen}>
              Admin
            </MobileItem>
          )}

          <button
            onClick={logout}
            className="block w-full text-left px-6 py-3 text-red-600 hover:bg-red-50"
          >
            Logout
          </button>

        </div>

      )}

    </nav>

  );

}


/* NAV ITEM */

function NavItem({ to, children, active }) {

  return (

    <Link
      to={to}
      className={`relative transition
      ${active ? "text-blue-600" : "text-gray-700 hover:text-blue-600"}`}
    >

      {children}

      <span
        className={`absolute left-0 -bottom-1 h-0.5 bg-blue-600 transition-all duration-300
        ${active ? "w-full" : "w-0 hover:w-full"}`}
      />

    </Link>

  );

}


/* MOBILE ITEM */

function MobileItem({ to, children, setOpen }) {

  return (

    <Link
      to={to}
      onClick={() => setOpen(false)}
      className="block px-6 py-3 text-gray-700 hover:bg-gray-100"
    >

      {children}

    </Link>

  );

}
